package main

import "fmt"

type ListNode struct {
	Val  int
	Next *ListNode
}

func reverseKGroup(head *ListNode, k int) *ListNode {
	dummy := &ListNode{Next: head}
	pre := dummy
	cur := head
	for cur != nil {
		tail := cur
		count := 1
		for count < k && tail.Next != nil {
			tail = tail.Next
			count++
		}
		nextGroup := tail.Next
		newHead, newTail := reverse(cur, tail)
		pre.Next = newHead
		newTail.Next = nextGroup
		pre = newTail
		cur = nextGroup
	}
	return dummy.Next
}

func reverse(head, tail *ListNode) (*ListNode, *ListNode) {
	prev := tail.Next
	cur := head
	for prev != tail {
		next := cur.Next
		cur.Next = prev
		prev = cur
		cur = next
	}
	return tail, head
}

func buildList(nums []int) *ListNode {
	dummy := &ListNode{}
	cur := dummy
	for _, num := range nums {
		cur.Next = &ListNode{Val: num}
		cur = cur.Next
	}
	return dummy.Next
}

func printList(head *ListNode) {
	for head != nil {
		fmt.Print(head.Val)
		if head.Next != nil {
			fmt.Print(" -> ")
		}
		head = head.Next
	}
	fmt.Println()
}

func main() {
	head := buildList([]int{1, 2, 3, 4, 5, 6, 7, 8})
	k := 3
	newHead := reverseKGroup(head, k)
	printList(newHead)
}
